// Support both Kardama.ai webhook (camelCase) and Supabase DB webhook (snake_case)
const raw = $input.first().json.body?.record ?? $input.first().json;

const name    = raw.customerName    || raw.customer_name    || '';
const email   = raw.customerEmail   || raw.customer_email   || '';
const phone   = raw.customerPhone   || raw.customer_phone   || '';
const addr    = raw.address         || '';
const unit    = raw.unit            || '';
const city    = raw.city            || '';
const hSize   = raw.homeSize        || raw.home_size        || '';
const freq    = raw.cleaningFrequency || raw.cleaning_frequency || '';
const payment = raw.paymentMethod   || raw.payment_method   || 'Not specified';
const pets    = raw.hasPetsAllergies || raw.has_pets_allergies || '';
const notes   = raw.notes           || '';
const date    = raw.preferredDate   || raw.preferred_date   || '';
const svcType = raw.serviceType     || raw.service_type     || '';

const manageUrl     = raw.manageUrl     || '';
const rescheduleUrl = raw.rescheduleUrl || '';
const cancelUrl     = raw.cancelUrl     || '';

// Parse time from either 24h ('08:00') or 12h ('8:00am')
function parseTime(t) {
  if (!t) return '10:00';
  const m24 = String(t).match(/^(\d{1,2}):(\d{2})$/);
  if (m24) return `${String(parseInt(m24[1])).padStart(2,'0')}:${m24[2]}`;
  const m12 = String(t).match(/(\d+):(\d+)(am|pm)/i);
  if (!m12) return '10:00';
  let h = parseInt(m12[1]);
  if (m12[3].toLowerCase() === 'pm' && h !== 12) h += 12;
  if (m12[3].toLowerCase() === 'am' && h === 12) h = 0;
  return `${String(h).padStart(2,'0')}:${m12[2]}`;
}

function to12h(t) {
  const m = String(t).match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return t;
  let h = parseInt(m[1]); const min = m[2];
  const p = h < 12 ? 'AM' : 'PM';
  if (h === 0) h = 12; else if (h > 12) h -= 12;
  return `${h}:${min} ${p}`;
}

function addHours(time, n) {
  const [h, m] = time.split(':').map(Number);
  return `${String(Math.min(h + n, 23)).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
}

const rawTime  = raw.preferredTime || (raw.preferred_arrival_times || [])[0];
const start24  = parseTime(rawTime);
const end24    = addHours(start24, 2);
const display  = to12h(start24);
const fullAddr = unit ? `${addr}, Unit ${unit}` : addr;

return [{
  json: {
    id:                   raw.bookingId || raw.id,
    customer_name:        name,
    first_name:           name.split(' ')[0],
    customer_email:       email,
    customer_phone:       phone,
    city,
    address:              fullAddr,
    home_size:            hSize,
    cleaning_frequency:   freq,
    service_type:         svcType,
    payment_method:       payment,
    has_pets_allergies:   pets,
    notes,
    preferred_date:       date,
    arrival_time_display: display,
    start_datetime:       `${date}T${start24}:00`,
    end_datetime:         `${date}T${end24}:00`,
    manage_url:           manageUrl,
    reschedule_url:       rescheduleUrl,
    cancel_url:           cancelUrl
  }
}];

